"""Deploy audit logger — writes structured JSON logs for every orchestrator run.

Log files are written to the 'logs/' directory with timestamped filenames.
Each log captures: command, user, params (secrets masked), module outcomes, and timing.
"""

from __future__ import annotations

import getpass
import json
import os
import platform
import sys
from datetime import datetime, timezone
from pathlib import Path

LOGS_DIR = "logs"

# Param names that should be masked in logs
_SENSITIVE_PATTERNS = {"email", "secret", "password", "token", "key", "credential"}


def _mask_value(key: str, value: str) -> str:
    """Mask sensitive param values for logging."""
    key_lower = key.lower()
    for pattern in _SENSITIVE_PATTERNS:
        if pattern in key_lower:
            if len(value) > 4:
                return value[:4] + "***"
            return "***"
    # Also mask resolved references
    if isinstance(value, str) and any(value.startswith(p) for p in ("ssm:", "secretsmanager:", "env:")):
        return value  # Still a reference, not resolved yet — safe to log
    return value


def _safe_params(params: dict) -> dict:
    """Return a copy of params with sensitive values masked."""
    return {k: _mask_value(k, str(v)) for k, v in params.items()}


class DeployLogger:
    """Structured audit logger for orchestrator runs."""

    def __init__(self, command: str, manifest: dict):
        self.start_time = datetime.now(timezone.utc)
        self.log_entry = {
            "timestamp": self.start_time.isoformat(),
            "command": command,
            "project": manifest.get("project", ""),
            "user": _get_user_info(),
            "params": _safe_params(manifest.get("params", {})),
            "modules": [m.split("@")[0] for m in manifest.get("modules", [])],
            "events": [],
            "result": None,
        }
        self._log_path = self._create_log_path(command)

    def _create_log_path(self, command: str) -> Path:
        """Create the log file path."""
        logs_dir = Path(LOGS_DIR)
        logs_dir.mkdir(exist_ok=True)
        ts = self.start_time.strftime("%Y%m%d-%H%M%S")
        return logs_dir / f"{ts}-{command}.json"

    def log_event(self, event_type: str, module: str | None = None, **kwargs) -> None:
        """Record a timestamped event."""
        event = {
            "time": datetime.now(timezone.utc).isoformat(),
            "type": event_type,
        }
        if module:
            event["module"] = module
        event.update(kwargs)
        self.log_entry["events"].append(event)

    def log_module_start(self, module: str, iac_type: str) -> None:
        self.log_event("module_start", module=module, iac_type=iac_type)

    def log_module_success(self, module: str) -> None:
        self.log_event("module_success", module=module)

    def log_module_failure(self, module: str, exit_code: int) -> None:
        self.log_event("module_failure", module=module, exit_code=exit_code)

    def finish(self, result: str, deployed: list[str] | None = None, failed: str | None = None) -> None:
        """Finalize the log with the overall result and write to disk."""
        end_time = datetime.now(timezone.utc)
        self.log_entry["result"] = result
        self.log_entry["duration_seconds"] = (end_time - self.start_time).total_seconds()
        if deployed is not None:
            self.log_entry["deployed"] = deployed
        if failed is not None:
            self.log_entry["failed"] = failed
        self.log_entry["finished_at"] = end_time.isoformat()
        self._write()

    def _write(self) -> None:
        """Write the log entry to disk."""
        try:
            self._log_path.write_text(json.dumps(self.log_entry, indent=2))
        except OSError as e:
            print(f"  WARNING: Failed to write deploy log: {e}", file=sys.stderr)


def _get_user_info() -> dict:
    """Gather user/environment info for the audit log."""
    return {
        "username": getpass.getuser(),
        "hostname": platform.node(),
        "cwd": os.getcwd(),
    }

"""Cost estimator — provides deployment cost estimates for selected modules.

Uses a combination of:
1. Known QuickSight pricing tiers (the primary cost driver)
2. Infrastructure cost notes per module (most are free-tier or negligible)
3. Optional infracost integration for detailed IaC cost breakdowns
"""

from __future__ import annotations

import shutil
import subprocess
from pathlib import Path

# QuickSight pricing (us-east-1, monthly, per user)
# Source: https://aws.amazon.com/quicksight/pricing/
QUICKSIGHT_PRICING = {
    "READER": {"monthly": 5.0, "annual_monthly": 3.0},
    "READER_PRO": {"monthly": 10.0, "annual_monthly": 8.0},
    "AUTHOR": {"monthly": 24.0, "annual_monthly": 18.0},
    "AUTHOR_PRO": {"monthly": 35.0, "annual_monthly": 25.0},
    "ADMIN": {"monthly": 24.0, "annual_monthly": 18.0},
    "ADMIN_PRO": {"monthly": 35.0, "annual_monthly": 25.0},
}

# Per-module infrastructure cost notes
MODULE_COST_NOTES: dict[str, dict] = {
    "governance/subscription": {
        "resources": "Lambda function, IAM roles, CloudFormation custom resource",
        "estimated_monthly": 0.0,
        "note": "Lambda runs only during deploy/update. No ongoing compute cost.",
    },
    "governance/permissions": {
        "resources": "IAM Identity Center permission sets",
        "estimated_monthly": 0.0,
        "note": "IAM Identity Center permission sets are free.",
    },
    "data-sources/redshift": {
        "resources": "QuickSight data source configuration",
        "estimated_monthly": 0.0,
        "note": "Data source config only. Redshift cluster cost is separate.",
    },
    "data-sources/athena": {
        "resources": "QuickSight data source, S3 results bucket",
        "estimated_monthly": 0.0,
        "note": "Athena charges per query ($5/TB scanned). S3 storage is minimal.",
    },
    "data-sources/glue": {
        "resources": "QuickSight data source configuration",
        "estimated_monthly": 0.0,
        "note": "Data source config only. Glue catalog is free for first 1M objects.",
    },
    "core/custom-resources": {
        "resources": "Lambda function (shared)",
        "estimated_monthly": 0.0,
        "note": "Runs only during deploy. Covered by Lambda free tier.",
    },
}


def estimate_quicksight_cost(manifest: dict) -> dict:
    """Estimate QuickSight licensing cost based on manifest params."""
    edition = manifest.get("params", {}).get("edition", "ENTERPRISE").upper()
    is_pro = "PRO" in edition or edition == "ENTERPRISE"

    return {
        "edition": edition,
        "pricing_note": "QuickSight is the primary cost driver. Infrastructure costs are negligible.",
        "per_user_monthly": {
            role: pricing["monthly"]
            for role, pricing in QUICKSIGHT_PRICING.items()
            if (is_pro and "PRO" in role) or (not is_pro and "PRO" not in role)
        },
        "tip": "Use annual commitment pricing for 20-30% savings.",
    }


def estimate_module_costs(modules: list[str]) -> list[dict]:
    """Return cost notes for each selected module."""
    results = []
    for mod in modules:
        info = MODULE_COST_NOTES.get(mod)
        if info:
            results.append({"module": mod, **info})
        else:
            results.append({
                "module": mod,
                "resources": "Unknown",
                "estimated_monthly": None,
                "note": "No cost estimate available for this module.",
            })
    return results


def try_infracost(manifest: dict) -> str | None:
    """Run infracost if available. Returns output or None."""
    if not shutil.which("infracost"):
        return None

    tf_dir = Path("templates/customer-project/tf-app")
    if not tf_dir.exists():
        return None

    try:
        result = subprocess.run(
            ["infracost", "breakdown", "--path", str(tf_dir), "--format", "table"],
            capture_output=True, text=True, timeout=120,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except (subprocess.TimeoutExpired, FileNotFoundError):
        pass
    return None


def print_cost_report(manifest: dict, ordered: list[str]) -> None:
    """Print a cost estimation report for the selected modules."""
    print("\n=== Cost Estimation ===\n")

    # QuickSight licensing
    qs = estimate_quicksight_cost(manifest)
    print(f"QuickSight Edition: {qs['edition']}")
    print(f"\n  {qs['pricing_note']}\n")
    print("  Per-user monthly pricing:")
    for role, price in qs["per_user_monthly"].items():
        print(f"    {role:15s}  ${price:.2f}/month")
    print(f"\n  Tip: {qs['tip']}\n")

    # Module infrastructure costs
    print("Module infrastructure costs:\n")
    module_costs = estimate_module_costs(ordered)
    total_infra = 0.0
    for mc in module_costs:
        cost_str = f"${mc['estimated_monthly']:.2f}/mo" if mc["estimated_monthly"] is not None else "unknown"
        print(f"  [{mc['module']}]")
        print(f"    Resources: {mc['resources']}")
        print(f"    Cost: {cost_str}")
        print(f"    Note: {mc['note']}\n")
        if mc["estimated_monthly"] is not None:
            total_infra += mc["estimated_monthly"]

    print(f"  Total infrastructure: ${total_infra:.2f}/month")
    print(f"  (QuickSight user licensing is additional — see per-user pricing above)\n")

    # Try infracost for detailed breakdown
    print("Checking for infracost...")
    infracost_output = try_infracost(manifest)
    if infracost_output:
        print(f"\n  Infracost detailed breakdown:\n")
        for line in infracost_output.split("\n"):
            print(f"    {line}")
    else:
        print("  infracost not found — install it for detailed IaC cost breakdowns:")
        print("  https://www.infracost.io/docs/")

    print("\n" + "=" * 50)
    print("Note: This is an estimate. Actual costs depend on usage patterns,")
    print("data volumes, and QuickSight user count. Review AWS pricing pages")
    print("for current rates: https://aws.amazon.com/quicksight/pricing/")

#!/usr/bin/env npx ts-node
/**
 * Synthesizes a single CDK module into a standalone CloudFormation template.
 *
 * Usage:
 *   npx ts-node core/synth-cfn-template.ts governance/subscription
 *
 * Outputs:
 *   governance/subscription/cfn-template.yaml
 *
 * The template uses CloudFormation Parameters so Terraform wrappers can
 * pass values in without needing the CDK CLI.
 */
import { App, CfnParameter, Stack } from 'aws-cdk-lib';
import { readFileSync, writeFileSync } from 'fs';
import { load } from 'js-yaml';
import { resolve } from 'path';

// --- Module registry ---
// Each CDK module must be registered here with its construct and param mapping.
import { QuickSuiteSubscription } from '../governance/subscription/cdk';
import { QuickSuitePermissions } from '../governance/permissions/cdk';
import { RedshiftDataSource } from '../data-sources/redshift/cdk';
import { AthenaDataSource } from '../data-sources/athena/cdk';
import { GlueDataSource } from '../data-sources/glue/cdk';

interface ModuleConfig {
  name: string;
  params: { name: string; required?: boolean; default?: string }[];
}

function loadModuleConfig(modulePath: string): ModuleConfig {
